function expandSection(section, targetLevel) {
  return section.nodes.map(node => {
    const currentDetail = node.detail[section.activeDetailLevel];
    const targetDetail = node.detail[targetLevel];

    // Ask AI to interpolate
    const prompt = `
      Expand from: "${currentDetail}"
      To approximately: ${targetDetail.length} chars
      Maintaining: ${node.core}
      Add: ${transformRules.expand[node.type][`${section.activeDetailLevel} → ${targetLevel}`]}
    `;

    return aiExpand(prompt);
  });
}
