```javascript
function lockSemanticConstraints(sentence) {
  // Use dependency parser (spaCy, nlp.js, or simple regex)
  const deps = parseDepedencies(sentence);

  // Identify critical relationships
  const constraints = deps.filter(dep => 
    dep.importance > 0.8 || dep.constrains.length > 0
  );

  // Store in memory
  memory.sentenceConstraints[sentence.id] = {
    locked: true,
    constraints: constraints,
    allowedMutations: generateMutationSpace(constraints),
    // allowedMutations = set of words/phrases that can swap without breaking structure
  };

  return constraints;
}

function validateEdit(originalSentence, newSentence, constraints) {
  const oldDeps = parseDepedencies(originalSentence);
  const newDeps = parseDepedencies(newSentence);

  // Check: did locked constraints survive?
  const violatedConstraints = constraints.filter(constraint => {
    const oldRel = oldDeps.find(d => d.matches(constraint));
    const newRel = newDeps.find(d => d.matches(constraint));

    if (!newRel) return true;  // Constraint broken
    if (semanticDistance(oldRel, newRel) > threshold) return true;  // Too different

    return false;
  });

  return {
    valid: violatedConstraints.length === 0,
    violations: violatedConstraints,
    confidence: 1 - (violatedConstraints.length / constraints.length)
  };
}
```

