## **2. DFS for Constraint Propagation**

When user changes word X, do a **DFS from X** to find all dependent vertices:

```javascript
function propagateChange(changedWord, semanticGraph) {
  const visited = new Set();
  const affected = [];

  function dfs(vertex) {
    visited.add(vertex);

    // Find all outgoing edges (dependencies)
    const outgoing = semanticGraph.edges.filter(e => e.from === vertex);

    outgoing.forEach(edge => {
      if (!visited.has(edge.to)) {
        affected.push(edge.to);
        dfs(edge.to);  // Recursive: what depends on this?
      }
    });
  }

  dfs(changedWord);
  return affected;  // All words that must adapt
}
```

