  const [affectedSeeds, setAffectedSeeds] = useState(new Set());

  const performDFS = (startVertex) => {
    const visitedSet = new Set();
    const order = [];

    function dfs(vertex) {
      visitedSet.add(vertex);
      order.push(vertex);

      const outgoing = semanticGraph.edges.filter(e => e.from === vertex);
      outgoing.forEach(edge => {
        if (!visitedSet.has(edge.to)) {
          dfs(edge.to);
        }
      });
    }

    dfs(startVertex);
    return { order, visitedSet };
  };

  const findAffectedSeeds = (vertices) => {
    const affected = new Set();
    Object.entries(seeds).forEach(([seedId, seed]) => {
      const hasAffectedWord = seed.words.some(word => vertices.has(word));
      if (hasAffectedWord) {
        affected.add(seedId);
      }
