import React, { useState, useMemo } from 'react';

export default function SemanticGraphConstraints() {
  const semanticGraph = {
    vertices: [
      { id: 'accelerate', role: 'primary_action', locked: true, importance: 0.95 },
      { id: 'teams', role: 'scope', locked: false, importance: 0.8 },
      { id: 'productivity', role: 'target', locked: false, importance: 0.85 },
      { id: 'quality', role: 'target', locked: false, importance: 0.7 },
      { id: 'output', role: 'target', locked: false, importance: 0.75 },
    ],
    edges: [
      { from: 'accelerate', to: 'productivity', type: 'TREE', label: 'causal', weight: 1.0 },
      { from: 'accelerate', to: 'quality', type: 'TREE', label: 'causal', weight: 1.0 },
      { from: 'accelerate', to: 'teams', type: 'TREE', label: 'scope', weight: 1.0 },
      { from: 'teams', to: 'productivity', type: 'FORWARD', label: 'target_refinement', weight: 0.7 },
      { from: 'productivity', to: 'output', type: 'CROSS', label: 'synonym', weight: 0.3 },
      { from: 'quality', to: 'output', type: 'BACK', label: 'reinforcing', weight: 0.6 },
