  };

  const seeds = {
    seed1: { content: 'Build platform to accelerate how teams boost productivity.', words: ['build', 'accelerate', 'teams', 'productivity'] },
    seed2: { content: 'Create system enabling teams to enhance output quality.', words: ['create', 'teams', 'quality', 'output'] },
    seed3: { content: 'Speed up work for organizations to improve results.', words: ['speed', 'quality', 'organizations', 'results'] },
  };

  const [selectedVertex, setSelectedVertex] = useState('accelerate');

  const findArticulationVertices = useMemo(() => {
    const visited = new Set();
    const discovered = {};
    const finished = {};
    const parent = {};
    const reachableAncestor = {};
    let time = 0;

    function dfs(v, p = null) {
      visited.add(v);
      time++;
      discovered[v] = time;
      reachableAncestor[v] = v;
      parent[v] = p;

      const outgoing = semanticGraph.edges.filter(e => e.from === v);
      outgoing.forEach(edge => {
        const to = edge.to;
        if (!visited.has(to)) {
          dfs(to, v);
          if (discovered[reachableAncestor[to]] < discovered[reachableAncestor[v]]) {
            reachableAncestor[v] = reachableAncestor[to];
          }
        } else if (to !== p) {
          if (discovered[to] < discovered[reachableAncestor[v]]) {
            reachableAncestor[v] = to;
          }
        }
      });

      time++;
      finished[v] = time;
    }

    semanticGraph.vertices.forEach(v => {
      if (!visited.has(v.id)) {
        dfs(v.id);
      }
    });

    const articulation = [];
    semanticGraph.vertices.forEach(v => {
      const isRoot = parent[v.id] === null;
      const outgoing = semanticGraph.edges.filter(e => e.from === v.id);

      if (isRoot && outgoing.length > 1) {
        articulation.push({
          id: v.id,
          type: 'root',
          reason: 'Root with multiple children',
          criticality: 0.95,
        });
      } else if (!isRoot) {
        const descendants = semanticGraph.vertices.filter(u => {
          const isDescendant = discovered[u.id] > discovered[v.id] && finished[u.id] < finished[v.id];
          return isDescendant;
        });

        if (descendants.length > 0) {
          const canReachBack = reachableAncestor[v.id] === v.id;
          if (canReachBack) {
            articulation.push({
              id: v.id,
              type: 'bridge',
              reason: `Bridges ${descendants.length} descendants`,
              criticality: (descendants.length * 0.5) / semanticGraph.vertices.length,
            });
          }
        }
      }
    });

    return articulation.sort((a, b) => b.criticality - a.criticality);
  }, []);

  const getConstraintStrength = (edgeType) => {
    const strengths = {
      TREE: { level: 'HARD', value: 1.0, color: '#c41e3a' },
      BACK: { level: 'STRONG', value: 0.8, color: '#0066cc' },
      FORWARD: { level: 'MEDIUM', value: 0.6, color: '#ffb800' },
      CROSS: { level: 'WEAK', value: 0.3, color: '#cccccc' },
    };
    return strengths[edgeType];
  };

  const evaluationOrder = useMemo(() => {
    const vertex = selectedVertex;
    const isArticulation = findArticulationVertices.some(a => a.id === vertex);
    const isLocked = semanticGraph.vertices.find(v => v.id === vertex)?.locked;

    const directEdges = semanticGraph.edges.filter(e => e.from === vertex);

    const treeEdges = directEdges.filter(e => e.type === 'TREE').sort((a, b) => b.weight - a.weight);
    const backEdges = directEdges.filter(e => e.type === 'BACK').sort((a, b) => b.weight - a.weight);
    const forwardEdges = directEdges.filter(e => e.type === 'FORWARD').sort((a, b) => b.weight - a.weight);
    const crossEdges = directEdges.filter(e => e.type === 'CROSS').sort((a, b) => b.weight - a.weight);

    const sorted = [...treeEdges, ...backEdges, ...forwardEdges, ...crossEdges];

    return {
      vertex,
      isArticulation,
      isLocked,
      edges: sorted,
      treeCount: treeEdges.length,
      backCount: backEdges.length,
      forwardCount: forwardEdges.length,
      crossCount: crossEdges.length,
      totalConstraints: sorted.length,
    };
  }, [selectedVertex, findArticulationVertices]);

  const affectedAnalysis = useMemo(() => {
    const visited = new Set();
    const order = [];
    const constraints = [];

