        const strength = getConstraintStrength(edge.type);
        constraints.push({
          from: v,
          to: edge.to,
          type: edge.type,
          strength: strength.level,
          value: strength.value,
        });

        if (!visited.has(edge.to)) {
          dfs(edge.to);
        }
      });
    }

    dfs(selectedVertex);

    const affectedSeeds = new Set();
    Object.entries(seeds).forEach(([seedId, seed]) => {
      const hasAffectedWord = seed.words.some(word => visited.has(word));
      if (hasAffectedWord) {
        affectedSeeds.add(seedId);
      }
    });

    return { order: Array.from(visited), affectedSeeds, constraints };
  }, [selectedVertex]);

  return (
    <div style={{ padding: '20px', fontFamily: 'system-ui', maxWidth: '1600px', margin: '0 auto' }}>
      <h1 style={{ marginTop: 0 }}>Dynamic Semantic Graph Constraint System</h1>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.2fr 1fr', gap: '20px', marginBottom: '30px' }}>

        <div style={{ border: '1px solid #ddd', borderRadius: '8px', padding: '15px' }}>
          <h2 style={{ marginTop: 0, fontSize: '14px', fontWeight: 600 }}>Articulation Vertices (DFS)</h2>
          <div style={{ fontSize: '11px', color: '#666', marginBottom: '10px' }}>Vertices whose deletion disconnects graph</div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
            {findArticulationVertices.map((vertex, idx) => {
              const isSelected = vertex.id === selectedVertex;
              return (
                <div
                  key={vertex.id}
                  onClick={() => setSelectedVertex(vertex.id)}
                  style={{
                    padding: '10px',
                    borderRadius: '4px',
                    border: isSelected ? '2px solid #c41e3a' : '1px solid #ddd',
                    backgroundColor: isSelected ? '#fff5f5' : '#f9f9f9',
                    cursor: 'pointer',
                  }}
                >
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                    <strong style={{ fontSize: '12px' }}>{idx + 1}. {vertex.id}</strong>
                    <span style={{ fontSize: '10px', backgroundColor: '#ffb800', padding: '2px 6px', borderRadius: '3px', color: '#fff' }}>
                      {vertex.type}
                    </span>
                  </div>
                  <div style={{ fontSize: '10px', color: '#666', marginBottom: '4px' }}>
                    {vertex.reason}
                  </div>
                  <div style={{ height: '4px', backgroundColor: '#eee', borderRadius: '2px', overflow: 'hidden' }}>
                    <div
                      style={{
                        height: '100%',
                        width: `${vertex.criticality * 100}%`,
                        backgroundColor: '#c41e3a',
                      }}
                    />
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div style={{ border: '2px solid #0066cc', borderRadius: '8px', padding: '15px', backgroundColor: '#f0f5ff' }}>
          <h2 style={{ marginTop: 0, fontSize: '14px', fontWeight: 600 }}>
            Constraint Evaluation Order (from "{selectedVertex}")
          </h2>
          <div style={{ fontSize: '11px', color: '#666', marginBottom: '12px' }}>
            CHANGES when you select different vertex. Locked vertices force TREE constraints first.
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginBottom: '12px' }}>
            <div style={{ padding: '8px', backgroundColor: '#fff', borderRadius: '4px', border: '1px solid #ddd' }}>
              <div style={{ fontSize: '10px', color: '#666' }}>Status</div>
              <div style={{ fontSize: '13px', fontWeight: 600 }}>
                {evaluationOrder.isArticulation ? '⚠️ ARTICULATION' : '✓ Regular'}
                {evaluationOrder.isLocked ? ' | 🔒 LOCKED' : ''}
              </div>
            </div>
            <div style={{ padding: '8px', backgroundColor: '#fff', borderRadius: '4px', border: '1px solid #ddd' }}>
              <div style={{ fontSize: '10px', color: '#666' }}>Total Constraints</div>
              <div style={{ fontSize: '13px', fontWeight: 600 }}>{evaluationOrder.totalConstraints}</div>
            </div>
          </div>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '6px', marginBottom: '12px' }}>
            <div style={{ padding: '8px', backgroundColor: '#fff', borderRadius: '4px', border: '2px solid #c41e3a' }}>
              <div style={{ fontSize: '10px', color: '#666' }}>TREE</div>
              <div style={{ fontSize: '14px', fontWeight: 600, color: '#c41e3a' }}>{evaluationOrder.treeCount}</div>
              <div style={{ fontSize: '9px', color: '#999' }}>Hard</div>
            </div>
            <div style={{ padding: '8px', backgroundColor: '#fff', borderRadius: '4px', border: '2px solid #0066cc' }}>
              <div style={{ fontSize: '10px', color: '#666' }}>BACK</div>
              <div style={{ fontSize: '14px', fontWeight: 600, color: '#0066cc' }}>{evaluationOrder.backCount}</div>
              <div style={{ fontSize: '9px', color: '#999' }}>Strong</div>
            </div>
            <div style={{ padding: '8px', backgroundColor: '#fff', borderRadius: '4px', border: '2px solid #ffb800' }}>
              <div style={{ fontSize: '10px', color: '#666' }}>FORWARD</div>
              <div style={{ fontSize: '14px', fontWeight: 600, color: '#ffb800' }}>{evaluationOrder.forwardCount}</div>
              <div style={{ fontSize: '9px', color: '#999' }}>Medium</div>
            </div>
            <div style={{ padding: '8px', backgroundColor: '#fff', borderRadius: '4px', border: '2px solid #cccccc' }}>
              <div style={{ fontSize: '10px', color: '#666' }}>CROSS</div>
              <div style={{ fontSize: '14px', fontWeight: 600, color: '#cccccc' }}>{evaluationOrder.crossCount}</div>
              <div style={{ fontSize: '9px', color: '#999' }}>Weak</div>
            </div>
          </div>

          <div style={{ fontSize: '11px', fontWeight: 600, marginBottom: '8px' }}>Evaluation Sequence:</div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
            {evaluationOrder.edges.map((edge, idx) => {
              const strength = getConstraintStrength(edge.type);
              return (
                <div
                  key={`${edge.from}-${edge.to}-${idx}`}
                  style={{
                    padding: '8px',
                    backgroundColor: '#fff',
                    borderRadius: '4px',
                    border: `2px solid ${strength.color}`,
                    display: 'flex',
                    justifyContent: 'space-between',
                    alignItems: 'center',
                  }}
                >
                  <div>
                    <span style={{ fontSize: '11px', fontWeight: 600 }}>
                      {idx + 1}. {edge.from} → {edge.to}
                    </span>
                    <div style={{ fontSize: '9px', color: '#666', marginTop: '2px' }}>
                      {edge.type} ({strength.level})
                    </div>
                  </div>
                  <div style={{ fontSize: '12px', fontWeight: 600, color: strength.color }}>
                    {Math.round(edge.weight * 100)}%
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div style={{ border: '1px solid #ddd', borderRadius: '8px', padding: '15px' }}>
          <h2 style={{ marginTop: 0, fontSize: '14px', fontWeight: 600 }}>Constraint Propagation</h2>

          <div style={{ marginBottom: '12px', padding: '10px', backgroundColor: '#ffe6e6', borderRadius: '4px' }}>
            <div style={{ fontSize: '11px', fontWeight: 600, color: '#c41e3a' }}>Reachable Vertices</div>
            <div style={{ fontSize: '13px', fontWeight: 600, marginTop: '4px' }}>
              {affectedAnalysis.order.length} / {semanticGraph.vertices.length}
            </div>
          </div>

          <div style={{ marginBottom: '12px' }}>
            <div style={{ fontSize: '11px', fontWeight: 600, marginBottom: '6px' }}>Path:</div>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '4px' }}>
              {affectedAnalysis.order.map((v, idx) => (
                <React.Fragment key={v}>
                  <span style={{ padding: '4px 8px', backgroundColor: '#f0f0f0', borderRadius: '3px', fontSize: '10px', fontWeight: 500 }}>
                    {v}
                  </span>
                  {idx < affectedAnalysis.order.length - 1 && (
                    <span style={{ fontSize: '10px', color: '#999' }}>→</span>
                  )}
                </React.Fragment>
              ))}
            </div>
          </div>

          <div style={{ marginBottom: '12px', padding: '10px', backgroundColor: '#f9f9f9', borderRadius: '4px' }}>
            <div style={{ fontSize: '11px', fontWeight: 600, marginBottom: '6px' }}>Affected Seeds</div>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
              {Object.keys(seeds).map(seedId => {
                const isAffected = affectedAnalysis.affectedSeeds.has(seedId);
                return (
                  <div
                    key={seedId}
                    style={{
                      padding: '6px',
                      borderRadius: '3px',
                      backgroundColor: isAffected ? '#fff5f5' : '#fff',
                      border: isAffected ? '1px solid #c41e3a' : '1px solid #ddd',
                      fontSize: '10px',
                    }}
                  >
                    {isAffected ? '⚠️' : '✓'} {seedId}
                  </div>
                );
              })}
            </div>
          </div>

          <div style={{ fontSize: '10px', color: '#999', lineHeight: '1.4' }}>
            <strong>Click vertices</strong> to see evaluation order change
          </div>
        </div>
      </div>

      <div style={{ padding: '15px', backgroundColor: '#f5f5f5', borderRadius: '8px', fontSize: '11px', lineHeight: '1.6' }}>
        <strong>What's Actually Changing Now:</strong>
        <ul style={{ margin: '8px 0', paddingLeft: '20px' }}>
          <li><strong>Constraint Evaluation Order</strong> = CHANGES based on selected vertex (see middle panel)</li>
          <li><strong>TREE constraints prioritized</strong> = Always evaluated first (hard constraints)</li>
          <li><strong>Articulation vertices detected via DFS</strong> = Using entry/exit times from Chapter 7</li>
          <li><strong>Locked vertices force reordering</strong> = Select "accelerate" (locked) vs "output" (unlocked) to see difference</li>
          <li><strong>Affected seeds</strong> = Shows which templates need updating based on what you changed</li>
        </ul>
      </div>
    </div>
  );
}
```

**Now test the actual changes:**
1. Click **"accelerate"** (locked articulation) → 3 TREE constraints
2. Click **"output"** (unlocked) → 0 outgoing constraints
3. Click **"teams"** → different mix (1 FORWARD, 0 others)

The **evaluation order in the blue panel actually changes** with each selection. That's the constraint propagation.
